// OwnershipScreen.jsx
import React, { useContext, useEffect } from "react";
import { View, Text, Pressable, StyleSheet } from "react-native";
import { AppContext } from "../../../App";
import { useFormNavigation } from "../../utils/navigationUtils";
import Header from "../../components/Header";
import { useTranslation } from "../../i18n"; // Import translation hook

const COLORS = {
  primary: "#14B8A6",
  secondary: "#7C3AED",
  background: "#F7F9FA",
  card: "#FFFFFF",
  textDark: "#1C1C1E",
  textMuted: "#6B7280",
};

export default function OwnershipScreen({ navigation }) {
  const { setFormProgress } = useContext(AppContext);
  const { updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation(); // Initialize translation hook

  useEffect(() => {
    updateCurrentStep("ownership_screen");
  }, []);

  const handleOwnerSelection = (isOwner) => {
    setFormProgress((prev) => ({
      ...prev,
      completedSteps: [
        ...new Set([...prev.completedSteps, "ownership_screen"]),
      ],
      currentStep: isOwner
        ? "vehicle_owner_form_screen"
        : "not_vehicle_owner_form_screen",
    }));

    navigation.navigate(
      isOwner
        ? "vehicle_owner_form_screen"
        : "not_vehicle_owner_form_screen"
    );
  };

  return (
    <View style={styles.screen}>
      {/* Header with logos */}
      <Header />

      {/* Custom back button added separately */}
      <Pressable
        style={styles.backButton}
        onPress={() => navigation.navigate("home_screen")}
      >
        <Text style={styles.backIcon}>←</Text>
      </Pressable>

      <View style={styles.content}>
        <Text style={styles.title}>
          {t("ownership.title")}
        </Text>

        <Text style={styles.subtitle}>
          {t("ownership.subtitle")}
        </Text>

        <View style={styles.choiceContainer}>
          {/* OUI */}
          <Pressable
            onPress={() => handleOwnerSelection(true)}
            style={({ pressed }) => [
              styles.choiceCard,
              styles.choiceYes,
              pressed && styles.pressed,
            ]}
          >
            <Text style={styles.choiceTitle}>{t("common.yes")}</Text>
            <Text style={styles.choiceDescription}>
              {t("ownership.yesDescription")}
            </Text>
          </Pressable>

          {/* NON */}
          <Pressable
            onPress={() => handleOwnerSelection(false)}
            style={({ pressed }) => [
              styles.choiceCard,
              styles.choiceNo,
              pressed && styles.pressed,
            ]}
          >
            <Text style={styles.choiceTitle}>{t("common.no")}</Text>
            <Text style={styles.choiceDescription}>
              {t("ownership.noDescription")}
            </Text>
          </Pressable>
        </View>

        <Text style={styles.helperText}>
          {t("ownership.helperText")}
        </Text>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    backgroundColor: COLORS.background,
    paddingHorizontal: 16,
  },
  content: {
    width: "100%",
    maxWidth: 520,
    alignSelf: "center",
  },
  backButton: {
    width: 42,
    height: 42,
    borderRadius: 12,
    backgroundColor: "#fff",
    alignItems: "center",
    justifyContent: "center",
    marginBottom: 8,
    marginTop: 16,
  },
  backIcon: {
    fontSize: 18,
    color: COLORS.textDark,
  },
  title: {
    fontSize: 24,
    fontWeight: "800",
    color: COLORS.textDark,
    textAlign: "center",
    marginBottom: 8,
  },
  subtitle: {
    fontSize: 15,
    color: COLORS.textMuted,
    textAlign: "center",
    marginBottom: 32,
  },
  choiceContainer: {
    gap: 16,
  },
  choiceCard: {
    backgroundColor: COLORS.card,
    borderRadius: 16,
    padding: 20,
    borderWidth: 1,
    borderColor: "#E5E7EB",
    shadowColor: "#000",
    shadowOpacity: 0.05,
    shadowRadius: 10,
    elevation: 3,
  },
  choiceYes: {
    borderLeftWidth: 5,
    borderLeftColor: COLORS.secondary,
  },
  choiceNo: {
    borderLeftWidth: 5,
    borderLeftColor: COLORS.primary,
  },
  pressed: {
    transform: [{ scale: 0.98 }],
  },
  choiceTitle: {
    fontSize: 18,
    fontWeight: "700",
    color: COLORS.textDark,
    marginBottom: 4,
  },
  choiceDescription: {
    fontSize: 14,
    color: COLORS.textMuted,
    lineHeight: 20,
  },
  helperText: {
    marginTop: 24,
    fontSize: 13,
    color: COLORS.textMuted,
    textAlign: "center",
  },
});
